require("fs"),async function(){console.log("Fetching products from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/products?pageSize=1000"),o=await e.json();if(!o.documents)return void console.error("No products found");console.log("Warming up main home page...");try{await fetch("https://speedgifts.net/"),console.log("Main page warmed up successfully.")}catch(e){console.error("Failed to warm up main page:",e)}console.log("Warming up shop page...");try{await fetch("https://speedgifts.net/shop"),console.log("Shop page warmed up successfully.")}catch(e){console.error("Failed to warm up shop page:",e)}const t=10;console.log("Fetching products to warm up...");const s=o.documents.map(e=>e.name.split("/").pop()).filter(e=>!["_ad_stats_","--global-stats_","_announcements_","_landing_settings_","_home_settings_","_hero_config_"].includes(e));console.log(`Fetched ${s.length} products to warm up.`);let a=0,c=0;for(let e=0;e<s.length;e+=t){const o=s.slice(e,e+t).map(async e=>{const o=`https://speedgifts.net/product/${encodeURIComponent(e)}`;try{(await fetch(o)).ok?a++:c++}catch(e){c++}});await Promise.all(o),await new Promise(e=>setTimeout(e,500)),console.log(`Product Progress: ${Math.min(e+t,s.length)} / ${s.length}`)}console.log(`Product Cache warming complete. Success: ${a}, Failed: ${c}`),console.log("Fetching categories from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/categories?pageSize=100"),o=await e.json();if(o.documents){const e=o.documents.map(e=>e.name.split("/").pop());console.log(`Fetched ${e.length} categories to warm up.`);let s=0,a=0;for(let o=0;o<e.length;o+=t){const c=e.slice(o,o+t).map(async e=>{const o=`https://speedgifts.net/shop?c=${encodeURIComponent(e)}`;try{(await fetch(o)).ok?s++:a++}catch(e){a++}});await Promise.all(c),await new Promise(e=>setTimeout(e,500)),console.log(`Category Progress: ${Math.min(o+t,e.length)} / ${e.length}`)}console.log(`Category Cache warming complete. Success: ${s}, Failed: ${a}`)}}catch(e){console.error("Failed to warm up categories:",e)}console.log("Manual Cache warming complete.")}catch(e){console.error("Error:",e)}}();